### 2.3 Protocol Buffer Definitions (ccs_proto/src/lib.rs)

```protobuf
// New module: pub mod fractional
pub mod fractional {
    use super::*;

    /// Request to fractionalize an existing NFT
    #[derive(Clone, PartialEq, Message)]
    pub struct FractionalizeRequest {
        #[prost(string, tag = "1")]
        pub nft_id: String,

        #[prost(string, tag = "2")]
        pub owner_wallet: String,

        #[prost(uint64, tag = "3")]
        pub total_fractions: u64,

        #[prost(uint64, tag = "4")]
        pub min_trade_unit: u64,

        #[prost(bool, tag = "5")]
        pub reconstitutable: bool,

        #[prost(uint64, optional, tag = "6")]
        pub buyout_price: Option<u64>,

        #[prost(bytes = "vec", tag = "7")]
        pub signature: Vec<u8>,
    }

    /// Response after successful fractionalization
    #[derive(Clone, PartialEq, Message)]
    pub struct FractionalizeResponse {
        #[prost(string, tag = "1")]
        pub fraction_token_id: String,

        #[prost(string, tag = "2")]
        pub tx_hash: String,

        #[prost(bool, tag = "3")]
        pub success: bool,
    }

    /// Query fraction holdings for a wallet
    #[derive(Clone, PartialEq, Message)]
    pub struct QueryFractionsRequest {
        #[prost(string, tag = "1")]
        pub wallet_address: String,

        #[prost(string, optional, tag = "2")]
        pub nft_id_filter: Option<String>,
    }

    /// Fraction holding record
    #[derive(Clone, PartialEq, Message)]
    pub struct FractionHolding {
        #[prost(string, tag = "1")]
        pub nft_id: String,

        #[prost(string, tag = "2")]
        pub fraction_token_id: String,

        #[prost(uint64, tag = "3")]
        pub balance: u64,

        #[prost(uint64, tag = "4")]
        pub total_supply: u64,

        #[prost(string, tag = "5")]
        pub nft_name: String,
    }

    /// Transfer fractions between wallets
    #[derive(Clone, PartialEq, Message)]
    pub struct TransferFractionsRequest {
        #[prost(string, tag = "1")]
        pub fraction_token_id: String,

        #[prost(string, tag = "2")]
        pub from_wallet: String,

        #[prost(string, tag = "3")]
        pub to_wallet: String,

        #[prost(uint64, tag = "4")]
        pub amount: u64,

        #[prost(bytes = "vec", tag = "5")]
        pub signature: Vec<u8>,
    }
}
```

### 2.4 State Database Changes (ccs_db/src/state_db.rs)

```rust
// New storage keys and methods to add:

impl StateDb {
    /// Key prefix for fraction ownership records
    const FRACTION_PREFIX: &'static [u8] = b"frac:";

    /// Key prefix for fraction metadata
    const FRACTION_META_PREFIX: &'static [u8] = b"frac_meta:";

    /// Store fraction balance for a wallet
    pub fn set_fraction_balance(
        &self,
        fraction_token_id: &[u8; 32],
        wallet: &Address,
        balance: u64,
    ) -> Result<StateRoot, StateDbError> {
        let key = self.compose_fraction_key(fraction_token_id, wallet);
        self.commit_block(WriteSet::from([WriteOp::Put(key, balance)]))
    }

    /// Get fraction balance for a wallet
    pub fn get_fraction_balance(
        &self,
        fraction_token_id: &[u8; 32],
        wallet: &Address,
    ) -> Result<Option<u64>, StateDbError> {
        let key = self.compose_fraction_key(fraction_token_id, wallet);
        self.get::<u64>(&key)
    }

    /// List all fraction holders for a token
    pub fn list_fraction_holders(
        &self,
        fraction_token_id: &[u8; 32],
    ) -> Result<Vec<(Address, u64)>, StateDbError> {
        // Scan with prefix to find all holders
        let prefix = self.compose_fraction_prefix(fraction_token_id);
        // Implementation details...
    }

    fn compose_fraction_key(&self, token_id: &[u8; 32], wallet: &Address) -> Vec<u8> {
        let mut key = Self::FRACTION_PREFIX.to_vec();
        key.extend_from_slice(token_id);
        key.extend_from_slice(wallet.as_bytes());
        key
    }
}
