#[tonic::async_trait]
impl WalletService for WalletRpcServer {
    // Existing methods...

    /// Query all fractional NFT holdings for a wallet
    async fn get_fraction_holdings(
        &self,
        request: Request<GetFractionHoldingsRequest>,
    ) -> Result<Response<GetFractionHoldingsResponse>, Status> {
        let wallet_id = request.into_inner().wallet_id;

        // Query state DB for all fraction balances
        let holdings = self.state_db
            .list_fraction_holdings_for_wallet(&wallet_id)
            .await
            .map_err(|e| Status::internal(e.to_string()))?;

        Ok(Response::new(GetFractionHoldingsResponse { holdings }))
    }

    /// Get detailed info about a specific fraction position
    async fn get_fraction_detail(
        &self,
        request: Request<GetFractionDetailRequest>,
    ) -> Result<Response<FractionDetail>, Status> {
        let req = request.into_inner();

        // Fetch fraction info + parent NFT metadata
        let detail = self.build_fraction_detail(&req.fraction_token_id, &req.wallet_id)
            .await
            .map_err(|e| Status::not_found(e.to_string()))?;

        Ok(Response::new(detail))
    }
}
