     2→//! Node service state–machine
     3→//!
     4→//! This module implements a hierarchical, asynchronous state-machine that
     5→//! drives a single CanvasChain Symphony “conductor” (validator / full node).
     6→//!
     7→//! The public façade is [`NodeStateMachine::spawn`].  Callers provide a
     8→//! configured [`NodeContext`] plus a Tokio `mpsc::Receiver<NodeEvent>` that
     9→//! represents the node’s inbound event bus.  
    10→//!
    11→//! The machine is built around the classic State pattern.  Each state
    12→//! implements [`State`]—an async callback that receives the next event and
    13→//! returns a [`Transition`] indicating whether the machine should:
    14→//!   * stay in the same state
    15→//!   * transition to a new boxed state
    16→//!   * perform a graceful shutdown.
    17→//!
    18→//! Transitions are **total**; all event/state combinations _must_ resolve to a
    19→//! `Transition`, preventing undefined behaviour at runtime.
    20→//!
    21→//! -------------------------------------------------------------------------
    22→//! Conventions & best-practices
    23→//! -------------------------------------------------------------------------
    24→//! • Logging is performed with the `tracing` crate (structured, async-aware).  
    25→//! • All public types derive `Debug` to make tracing easier.  
    26→//! • Errors bubble up using `thiserror::Error` and are logged before causing a
    27→//!   transition into [`StateError`].  
    28→//! • No blocking I/O—everything is fully async.  
    29→//! • `#![deny(clippy::unwrap_used)]` ensures we never `.unwrap()` outside of
    30→//!   tests.  
    31→//!
    32→//! -------------------------------------------------------------------------
    33→//! Example
    34→//! -------------------------------------------------------------------------
    35→//! ```no_run
    36→//! # use tokio::sync::mpsc;
    37→//! # use canvas_chain_node_service::state_machine::*;
    38→//! # #[tokio::main]
    39→//! # async fn main() -> anyhow::Result<()> {
    40→//! let (tx, rx) = mpsc::channel(128);
    41→//! let ctx = NodeContext::new(Default::default(), tx.clone());
    42→//! let handle = NodeStateMachine::spawn(ctx, rx);
    43→//!
    44→//! // Send a dummy event
    45→//! tx.send(NodeEvent::Tick).await?;
    46→//!
    47→//! // Wait until the machine exits
    48→//! handle.await?;
    49→//! # Ok::<_, anyhow::Error>(())
    50→//! # }
    51→//! ```
    52→
    53→#![deny(clippy::unwrap_used)]
    54→
    55→use std::time::Duration;
    56→
    57→use async_trait::async_trait;
    58→use tokio::{
    59→    select,
    60→    sync::mpsc,
    61→    task::JoinHandle,
    62→    time::{interval, Interval},
    63→};
    64→use tracing::{debug, error, info, instrument};
    65→
    66→use crate::event_bus::Publish;
    67→use crate::network::types::{Block, PeerId};
    68→use crate::storage::Database;
    69→
    70→// ------------------------------
    71→// Public facade
    72→// ------------------------------
    73→
    74→/// Spawn a state-machine on the Tokio runtime and return a [`JoinHandle`]
    75→/// representing its lifecycle.
    76→pub struct NodeStateMachine;
    77→
    78→impl NodeStateMachine {
    79→    /// Spawns the asynchronous state machine.  The function immediately returns
    80→    /// a Tokio [`JoinHandle`] that finishes when the machine reaches the
    81→    /// [`Transition::Shutdown`] transition or the provided `event_rx` closes.
    82→    pub fn spawn(
    83→        mut ctx: NodeContext,
    84→        mut event_rx: mpsc::Receiver<NodeEvent>,
    85→    ) -> JoinHandle<anyhow::Result<()>> {
    86→        tokio::spawn(async move {
    87→            let mut state: Box<dyn State> = Box::<StateBooting>::default();
    88→
    89→            // Heart-beat ticker; every state receives `Tick` events.
    90→            let mut ticker = interval(Duration::from_secs(5));
    91→
    92→            loop {
    93→                select! {
    94→                    maybe_evt = event_rx.recv() => {
    95→                        match maybe_evt {
    96→                            Some(evt) => {
    97→                                state = dispatch(&mut ctx, state, evt).await?;
    98→                            }
    99→                            None => {
   100→                                info!("event stream closed – shutting node down");
   101→                                break;
   102→                            }
   103→                        }
   104→                    }
   105→
   106→                    _ = ticker.tick() => {
   107→                        state = dispatch(&mut ctx, state, NodeEvent::Tick).await?;
   108→                    }
   109→                }
   110→            }
   111→
   112→            info!(node_id=%ctx.config.node_id, "node service terminated");
   113→            Ok(())
   114→        })
   115→    }
   116→}
   117→
   118→// ------------------------------
   119→// Context & Events
   120→// ------------------------------
   121→
   122→/// Immutable configuration for a running node.
   123→#[derive(Debug, Clone)]
   124→pub struct NodeConfig {
   125→    pub node_id: String,
   126→    pub network_id: String,
   127→    pub database_url: String,
   128→    pub is_validator: bool,
   129→}
   130→
   131→impl Default for NodeConfig {
   132→    fn default() -> Self {
   133→        Self {
   134→            node_id: nanoid::nanoid!(),
   135→            network_id: "canvas-testnet".into(),
   136→            database_url: "sqlite::memory:".into(),
   137→            is_validator: false,
   138→        }
   139→    }
   140→}
   141→
   142→/// Long-living, shared runtime context passed to every [`State`].
   143→#[derive(Debug)]
   144→pub struct NodeContext {
   145→    pub config: NodeConfig,
   146→    pub db: Database,
   147→    pub event_tx: mpsc::Sender<NodeEvent>,
   148→    pub bus: Publish, // Simplified, re-export from crate::event_bus
   149→}
   150→
   151→impl NodeContext {
   152→    pub fn new(config: NodeConfig, event_tx: mpsc::Sender<NodeEvent>) -> Self {
   153→        let db = Database::connect(&config.database_url)
   154→            .expect("infallible for in-memory; otherwise bubble up");
   155→
   156→        Self {
   157→            config,
   158→            db,
   159→            event_tx,
   160→            bus: Publish::default(),
   161→        }
   162→    }
   163→}
   164→
   165→/// All possible events handled by the state machine.
   166→#[derive(Debug)]
   167→pub enum NodeEvent {
   168→    /// Periodic internal heart-beat.
   169→    Tick,
   170→
   171→    /// New peer connected
   172→    PeerConnected(PeerId),
   173→
   174→    /// Network broadcast of a new block announcement.
   175→    BlockReceived(Block),
   176→
   177→    /// The consensus engine elected this node the next composer (“validator”).
   178→    ElectedComposer,
   179→
   180→    /// Graceful shutdown request.
   181→    Shutdown,
   182→}
   183→
   184→// ------------------------------
   185→// State machinery
   186→// ------------------------------
   187→
   188→/// When a [`State`] finishes processing an event it returns a `Transition`
   189→/// deciding the machine’s next state.
   190→#[derive(Debug)]
   191→pub enum Transition {
