   116→/// Simple, thread-safe in-memory repository.  
   117→/// In production this would be swapped for a SQL or KV store implementation.
   118→pub struct InMemoryListingRepository {
   119→    /// Internal map guarded by a read-write lock
   120→    listings: RwLock<HashMap<ListingId, Listing>>,
   121→}
   122→
   123→impl InMemoryListingRepository {
   124→    pub fn new() -> Self {
   125→        Self {
   126→            listings: RwLock::new(HashMap::new()),
   127→        }
   128→    }
   129→}
