   131→#[async_trait]
   132→impl ListingRepository for InMemoryListingRepository {
   133→    #[instrument(skip(self, listing))]
   134→    async fn insert(&self, listing: Listing) -> Result<(), ListingError> {
   135→        let mut map = self.listings.write().await;
   136→        map.insert(listing.id, listing);
   137→        Ok(())
   138→    }
   139→
   140→    #[instrument(skip(self))]
   141→    async fn get(&self, id: ListingId) -> Result<Listing, ListingError> {
   142→        let map = self.listings.read().await;
   143→        map.get(&id).cloned().ok_or(ListingError::NotFound)
   144→    }
   145→
   146→    #[instrument(skip(self, listing))]
   147→    async fn update(&self, listing: Listing) -> Result<(), ListingError> {
   148→        let mut map = self.listings.write().await;
   149→        map.insert(listing.id, listing);
   150→        Ok(())
   151→    }
   152→
   153→    #[instrument(skip(self))]
   154→    async fn list_active(&self) -> Result<Vec<Listing>, ListingError> {
   155→        let map = self.listings.read().await;
   156→        Ok(map
   157→            .values()
   158→            .filter(|l| matches!(l.status, ListingStatus::Active))
   159→            .cloned()
   160→            .collect())
   161→    }
   162→}
