   186→#[derive(Clone)]
   187→pub struct ListingManager<R: ListingRepository> {
   188→    repo: Arc<R>,
   189→    events: broadcast::Sender<MarketplaceEvent>,
   190→}
   191→
   192→/// Upper bound for potentially blocking database operations.
   193→const DB_OP_TIMEOUT: Duration = Duration::from_secs(3);
   194→
   195→impl<R: ListingRepository> ListingManager<R> {
   196→    pub fn new(repo: Arc<R>) -> Self {
   197→        let (tx, _) = broadcast::channel(256);
   198→        Self { repo, events: tx }
   199→    }
   200→
   201→    /// Subscribe to marketplace events.
   202→    pub fn subscribe(&self) -> broadcast::Receiver<MarketplaceEvent> {
   203→        self.events.subscribe()
   204→    }
   205→
   206→    #[instrument(skip(self))]
   207→    pub async fn create_listing(
   208→        &self,
   209→        owner: AccountId,
   210→        nft_contract: String,
   211→        token_id: String,
   212→        price: Decimal,
   213→    ) -> Result<ListingId, ListingError> {
   214→        let listing = Listing {
   215→            id: ListingId::new(),
   216→            owner,
   217→            nft_contract,
   218→            token_id,
   219→            price,
   220→            status: ListingStatus::Active,
   221→            created_at: Utc::now(),
   222→            updated_at: Utc::now(),
   223→        };
   224→
   225→        timeout(DB_OP_TIMEOUT, self.repo.insert(listing.clone()))
   226→            .await
   227→            .map_err(|_| ListingError::Timeout)?
   228→            ?;
   229→
   230→        self.dispatch_event(MarketplaceEvent::ListingCreated(listing))?;
   231→
   232→        Ok(listing.id)
   233→    }
   234→
   235→    #[instrument(skip(self))]
   236→    pub async fn reserve_listing(
   237→        &self,
   238→        listing_id: ListingId,
   239→        buyer: AccountId,
   240→    ) -> Result<(), ListingError> {
   241→        let mut listing = timeout(DB_OP_TIMEOUT, self.repo.get(listing_id))
   242→            .await
   243→            .map_err(|_| ListingError::Timeout)??
   244→            ;
   245→
   246→        match listing.status {
   247→            ListingStatus::Active => {
   248→                listing.status = ListingStatus::Reserved {
   249→                    buyer,
   250→                    reserved_at: Utc::now(),
   251→                };
   252→                listing.updated_at = Utc::now();
   253→            }
   254→            ListingStatus::Reserved { buyer: original, .. } if original == buyer => {
   255→                // Idempotent
   256→                return Ok(());
   257→            }
   258→            ListingStatus::Reserved { buyer: other, .. } => {
   259→                return Err(ListingError::Reserved(other));
   260→            }
   261→            ListingStatus::Sold => return Err(ListingError::AlreadySold),
   262→            ListingStatus::Cancelled => return Err(ListingError::AlreadyCancelled),
   263→        }
   264→
   265→        timeout(DB_OP_TIMEOUT, self.repo.update(listing.clone()))
   266→            .await
   267→            .map_err(|_| ListingError::Timeout)??
   268→            ;
   269→
   270→        self.dispatch_event(MarketplaceEvent::ListingReserved { listing_id, buyer })?;
   271→        Ok(())
   272→    }
