   275→    pub async fn cancel_listing(&self, listing_id: ListingId, caller: AccountId) -> Result<(), ListingError> {
   276→        let mut listing = timeout(DB_OP_TIMEOUT, self.repo.get(listing_id))
   277→            .await
   278→            .map_err(|_| ListingError::Timeout)??
   279→            ;
   280→
   281→        if listing.owner != caller {
   282→            return Err(ListingError::Repository("Only owner can cancel".into()));
   283→        }
   284→
   285→        match listing.status {
   286→            ListingStatus::Sold => return Err(ListingError::AlreadySold),
   287→            ListingStatus::Cancelled => return Err(ListingError::AlreadyCancelled),
   288→            _ => {}
   289→        }
   290→
   291→        listing.status = ListingStatus::Cancelled;
   292→        listing.updated_at = Utc::now();
   293→
   294→        timeout(DB_OP_TIMEOUT, self.repo.update(listing.clone()))
   295→            .await
   296→            .map_err(|_| ListingError::Timeout)??
   297→            ;
   298→
   299→        self.dispatch_event(MarketplaceEvent::ListingCancelled(listing_id))?;
   300→        Ok(())
   301→    }
