     2→//! Auction engine for the marketplace micro-service.
     3→//!
     4→//! Responsibilities
     5→//! ----------------
     6→//! 1. Create, store and track English auctions for multilayer NFTs.
     7→//! 2. Enforce bidding rules (reserve price, minimum increment, anti-sniping).
     8→//! 3. Periodically finalize ended auctions and emit events onto the service bus.
     9→//!
    10→//! The engine is designed for dependency-injection: any persistent storage that
    11→//! implements `AuctionStore` can be plugged in.  Out of the box we provide an
    12→//! in-memory implementation that is perfect for unit tests and local dev
    13→//! environments.
    14→//!
    15→//! The module is *asynchronous* and uses Tokio for non-blocking execution.
    16→//!
    17→//! # Example
    18→//! ```no_run
    19→//! # use marketplace_service::auction_engine::*;
    20→//! # #[tokio::main]
    21→//! # async fn main() -> anyhow::Result<()> {
    22→//! let engine = AuctionEngine::with_memory_store(Default::default());
    23→//!
    24→//! let auction_id = engine
    25→//!     .create_auction(CreateAuction {
    26→//!         nft_id: NftId::new(),
    27→//!         seller_id: UserId::new(),
    28→//!         reserve_price: 10_000,
    29→//!         duration: chrono::Duration::hours(24),
    30→//!     })
    31→//!     .await?;
    32→//!
    33→//! engine
    34→//!     .place_bid(auction_id, UserId::new(), 11_000)
    35→//!     .await?;
    36→//!
    37→//! // spawn finalize loop
    38→//! engine.clone().spawn_finalize_loop(tokio::time::Duration::from_secs(30));
    39→//! # Ok(()) }
    40→//! ```
    41→
    42→use std::{
    43→    collections::HashMap,
    44→    fmt,
    45→    sync::Arc,
    46→    time::Duration as StdDuration,
    47→};
    48→
    49→use async_trait::async_trait;
    50→use chrono::{DateTime, Duration, Utc};
    51→use serde::{Deserialize, Serialize};
    52→use thiserror::Error;
    53→use tokio::{
    54→    sync::{broadcast, RwLock},
    55→    task::JoinHandle,
    56→};
    57→use uuid::Uuid;
    58→
    59→/* -------------------------------------------------------------------------- */
    60→/*                                Type Aliases                                */
    61→/* -------------------------------------------------------------------------- */
    62→
    63→#[derive(Clone, Copy, Debug, Eq, PartialEq, Hash, Serialize, Deserialize)]
    64→pub struct AuctionId(Uuid);
    65→
    66→impl AuctionId {
    67→    pub fn new() -> Self {
    68→        Self(Uuid::new_v4())
    69→    }
    70→}
    71→
    72→#[derive(Clone, Copy, Debug, Eq, PartialEq, Hash, Serialize, Deserialize)]
    73→pub struct UserId(Uuid);
    74→
    75→impl UserId {
    76→    pub fn new() -> Self {
    77→        Self(Uuid::new_v4())
    78→    }
    79→}
    80→
    81→#[derive(Clone, Copy, Debug, Eq, PartialEq, Hash, Serialize, Deserialize)]
    82→pub struct NftId(Uuid);
    83→
    84→impl NftId {
    85→    pub fn new() -> Self {
    86→        Self(Uuid::new_v4())
    87→    }
    88→}
    89→
    90→/* -------------------------------------------------------------------------- */
    91→/*                                 DTOs / API                                 */
    92→/* -------------------------------------------------------------------------- */
    93→
    94→/// Immutable auction parameters used for construction.
    95→#[derive(Debug)]
    96→pub struct CreateAuction {
    97→    pub nft_id: NftId,
    98→    pub seller_id: UserId,
    99→    /// Minimum price in the platform's smallest denomination (e.g. wei).
   100→    pub reserve_price: u128,
   101→    /// How long the auction should stay active.
   102→    pub duration: Duration,
   103→}
   104→
   105→/// Public view of a bid.
   106→#[derive(Clone, Debug, Serialize, Deserialize)]
   107→pub struct Bid {
   108→    pub bidder_id: UserId,
   109→    pub amount: u128,
   110→    pub timestamp: DateTime<Utc>,
   111→}
   112→
   113→/* -------------------------------------------------------------------------- */
   114→/*                                  Domain                                    */
   115→/* -------------------------------------------------------------------------- */
   116→
   117→#[derive(Clone, Debug, Serialize, Deserialize)]
   118→pub enum AuctionStatus {
   119→    Pending,
   120→    Active,
   121→    Finalized,
   122→    Cancelled,
   123→}
   124→
   125→#[derive(Clone, Debug, Serialize, Deserialize)]
   126→pub struct Auction {
   127→    pub id: AuctionId,
   128→    pub nft_id: NftId,
   129→    pub seller_id: UserId,
   130→    pub reserve_price: u128,
   131→    pub start_time: DateTime<Utc>,
   132→    pub end_time: DateTime<Utc>,
   133→    pub status: AuctionStatus,
   134→    pub highest_bid: Option<Bid>,
   135→}
   136→
   137→impl Auction {
   138→    /// Returns whether the auction is open for bids.
   139→    pub fn is_active(&self, now: DateTime<Utc>) -> bool {
   140→        matches!(self.status, AuctionStatus::Active)
   141→            && now >= self.start_time
   142→            && now < self.end_time
   143→    }
   144→
   145→    /// Returns whether auction should be finalized (elapsed or cancelled).
   146→    pub fn should_finalize(&self, now: DateTime<Utc>) -> bool {
   147→        matches!(self.status, AuctionStatus::Active) && now >= self.end_time
   148→    }
   149→}
   150→
   151→/* -------------------------------------------------------------------------- */
   152→/*                                    Store                                   */
   153→/* -------------------------------------------------------------------------- */
   154→
   155→/// Storage abstraction. Can be backed by Postgres, Redis, RocksDB, etc.
   156→#[async_trait]
   157→pub trait AuctionStore: Send + Sync + 'static {
   158→    async fn insert(&self, auction: Auction) -> Result<(), EngineError>;
   159→    async fn update(&self, auction: &Auction) -> Result<(), EngineError>;
   160→    async fn get(&self, id: AuctionId) -> Result<Option<Auction>, EngineError>;
   161→    async fn all_due_for_finalize(
   162→        &self,
   163→        now: DateTime<Utc>,
   164→    ) -> Result<Vec<AuctionId>, EngineError>;
   165→}
   166→
   167→/* --------------------------- In-memory implementation --------------------------- */
   168→
   169→type AuctionMap = Arc<RwLock<HashMap<AuctionId, Auction>>>;
   170→
   171→/// An in-memory, thread-safe store backed by a `HashMap`.
   172→/// Meant for tests / local development, *not* production.
   173→#[derive(Clone, Default)]
   174→pub struct MemoryAuctionStore {
   175→    map: AuctionMap,
   176→}
   177→
   178→#[async_trait]
   179→impl AuctionStore for MemoryAuctionStore {
   180→    async fn insert(&self, auction: Auction) -> Result<(), EngineError> {
   181→        let mut map = self.map.write().await;
   182→        map.insert(auction.id, auction);
   183→        Ok(())
   184→    }
   185→
   186→    async fn update(&self, auction: &Auction) -> Result<(), EngineError> {
   187→        let mut map = self.map.write().await;
   188→        if let Some(a) = map.get_mut(&auction.id) {
   189→            *a = auction.clone();
   190→            Ok(())
   191→        } else {
   192→            Err(EngineError::AuctionNotFound)
   193→        }
   194→    }
   195→
   196→    async fn get(&self, id: AuctionId) -> Result<Option<Auction>, EngineError> {
   197→        let map = self.map.read().await;
   198→        Ok(map.get(&id).cloned())
   199→    }
   200→
   201→    async fn all_due_for_finalize(
   202→        &self,
   203→        now: DateTime<Utc>,
   204→    ) -> Result<Vec<AuctionId>, EngineError> {
   205→        let map = self.map.read().await;
   206→        Ok(map
   207→            .values()
   208→            .filter(|a| a.should_finalize(now))
   209→            .map(|a| a.id)
   210→            .collect())
   211→    }
   212→}
   213→
   214→/* -------------------------------------------------------------------------- */
   215→/*                               Event definitions                            */
   216→/* -------------------------------------------------------------------------- */
   217→
   218→#[derive(Clone, Debug, Serialize, Deserialize)]
   219→pub enum AuctionEvent {
   220→    AuctionCreated(AuctionId),
   221→    BidPlaced {
   222→        auction_id: AuctionId,
   223→        bidder_id: UserId,
   224→        amount: u128,
   225→    },
   226→    AuctionFinalized {
   227→        auction_id: AuctionId,
   228→        winner: Option<UserId>,
   229→        amount: Option<u128>,
   230→    },
   231→    AuctionCancelled(AuctionId),
   232→}
   233→
   234→/* -------------------------------------------------------------------------- */
   235→/*                               Error handling                               */
   236→/* -------------------------------------------------------------------------- */
   237→
   238→#[derive(Debug, Error)]
   239→pub enum EngineError {
   240→    #[error("auction not found")]
   241→    AuctionNotFound,
   242→    #[error("auction is not active")]
   243→    AuctionNotActive,
   244→    #[error("bid below reserve price")]
   245→    ReserveNotMet,
   246→    #[error("bid increment too low")]
   247→    IncrementTooLow,
   248→    #[error("seller cannot bid on own auction")]
   249→    SellerCannotBid,
   250→    #[error("auction already finalized or cancelled")]
   251→    InvalidAuctionState,
   252→    #[error("storage error: {0}")]
   253→    Storage(#[from] anyhow::Error),
   254→    #[error("broadcast error")]
   255→    Broadcast,
   256→}
   257→
   258→/* -------------------------------------------------------------------------- */
   259→/*                                AuctionEngine                               */
   260→/* -------------------------------------------------------------------------- */
   261→
   262→#[derive(Clone)]
   263→pub struct AuctionEngine<S: AuctionStore> {
   264→    store: Arc<S>,
   265→    /// Minimum bid increment (e.g. 1% of current highest) expressed as basis points.
   266→    min_increment_bps: u16,
   267→    /// Tokio broadcast channel for events.
   268→    event_tx: broadcast::Sender<AuctionEvent>,
   269→}
   270→
   271→impl<S: AuctionStore> AuctionEngine<S> {
   272→    /// Create an engine using the provided store.
   273→    pub fn new(store: S, min_increment_bps: u16) -> Self {
   274→        let (event_tx, _) = broadcast::channel(1024);
   275→        Self {
   276→            store: Arc::new(store),
   277→            min_increment_bps,
   278→            event_tx,
   279→        }
   280→    }
   281→
   282→    /// Convenience helper for tests/local dev.
   283→    pub fn with_memory_store(config: EngineConfig) -> Self {
   284→        Self::new(MemoryAuctionStore::default(), config.min_increment_bps)
   285→    }
   286→
   287→    /// Subscribe to auction events (fire-and-forget).
   288→    pub fn subscribe(&self) -> broadcast::Receiver<AuctionEvent> {
   289→        self.event_tx.subscribe()
   290→    }
   291→
   292→    /* ----------------------------- API methods ----------------------------- */
   293→
   294→    /// Creates an auction and stores it. Emits `AuctionCreated`.
   295→    pub async fn create_auction(
   296→        &self,
   297→        params: CreateAuction,
   298→    ) -> Result<AuctionId, EngineError> {
   299→        let now = Utc::now();
   300→        let auction = Auction {
   301→            id: AuctionId::new(),
   302→            nft_id: params.nft_id,
   303→            seller_id: params.seller_id,
   304→            reserve_price: params.reserve_price,
   305→            start_time: now,
   306→            end_time: now + params.duration,
   307→            status: AuctionStatus::Active,
   308→            highest_bid: None,
   309→        };
   310→        self.store.insert(auction.clone()).await?;
   311→        self.emit(AuctionEvent::AuctionCreated(auction.id))?;
   312→        Ok(auction.id)
   313→    }
