    35→    #[error("storage error: {0}")]
    36→    Storage(String),
    37→    #[error("signature verification failed")]
    38→    InvalidSignature,
    39→    #[error("proposal not found: {0}")]
    40→    NotFound(Uuid),
    41→    #[error("vote already cast by voter")]
    42→    DuplicateVote,
    43→    #[error("proposal already finalized")]
