   143→/// Signature verification strategy.  Each wallet/curve implementation
   144→/// can plug its own verifier (Ed25519, BLS, post-quantum…).
   145→#[async_trait]
   146→pub trait SignatureVerifier: Send + Sync + 'static {
   147→    async fn verify(
   148→        &self,
   149→        wallet_address: &str,
   150→        payload: &[u8],
   151→        signature: &[u8],
   152→    ) -> Result<(), ProposalError>;
