   155→/// A default in-memory storage for local testing.
   156→///
   157→/// THIS IS NOT SUITABLE FOR PRODUCTION but helps keeping the code
   158→/// self-contained for demonstration purposes.
   159→#[derive(Default)]
   160→pub struct InMemoryStore {
   161→    proposals: RwLock<HashMap<Uuid, Proposal>>,
   162→}
   163→
   164→#[async_trait]
   165→impl ProposalStore for InMemoryStore {
   166→    async fn save_proposal(&self, proposal: &Proposal) -> Result<(), ProposalError> {
   167→        self.proposals
   168→            .write()
   169→            .await
   170→            .insert(proposal.id, proposal.clone());
   171→        Ok(())
   172→    }
   173→
   174→    async fn load_proposal(&self, id: Uuid) -> Result<Proposal, ProposalError> {
   175→        self.proposals
   176→            .read()
   177→            .await
   178→            .get(&id)
   179→            .cloned()
   180→            .ok_or(ProposalError::NotFound(id))
   181→    }
   182→
   183→    async fn save_vote(
   184→        &self,
   185→        proposal_id: Uuid,
   186→        voter: &str,
   187→        choice: VoteChoice,
   188→    ) -> Result<(), ProposalError> {
   189→        let mut map = self.proposals.write().await;
   190→        let proposal = map
   191→            .get_mut(&proposal_id)
   192→            .ok_or(ProposalError::NotFound(proposal_id))?;
   193→
   194→        if proposal.status != ProposalStatus::Active {
   195→            return Err(ProposalError::Finalized);
   196→        }
   197→        if proposal.votes.contains_key(voter) {
   198→            return Err(ProposalError::DuplicateVote);
   199→        }
   200→
   201→        proposal.votes.insert(voter.to_owned(), choice);
   202→        Ok(())
   203→    }
   204→
   205→    async fn list_active(&self) -> Result<Vec<Proposal>, ProposalError> {
   206→        Ok(self
   207→            .proposals
   208→            .read()
   209→            .await
   210→            .values()
   211→            .filter(|p| p.status == ProposalStatus::Active)
   212→            .cloned()
   213→            .collect())
   214→    }
   215→
   216→    async fn finalize(
   217→        &self,
   218→        proposal_id: Uuid,
   219→        _outcome: ProposalOutcome,
   220→    ) -> Result<(), ProposalError> {
   221→        let mut map = self.proposals.write().await;
   222→        let proposal = map
   223→            .get_mut(&proposal_id)
   224→            .ok_or(ProposalError::NotFound(proposal_id))?;
   225→        proposal.status = ProposalStatus::Finalized;
   226→        Ok(())
   227→    }
   228→}
