   240→/// The main façade exposed to the outer world.  All methods are
   241→/// thread-safe and async aware.
   242→pub struct ProposalEngine<S, E, V>
   243→where
   244→    S: ProposalStore,
   245→    E: EventPublisher,
   246→    V: SignatureVerifier,
