   256→impl<S, E, V> ProposalEngine<S, E, V>
   257→where
   258→    S: ProposalStore,
   259→    E: EventPublisher,
   260→    V: SignatureVerifier,
   261→{
   262→    pub fn new(store: Arc<S>, events: Arc<E>, verifier: Arc<V>) -> Self {
   263→        let config = GovernanceParameters {
