   104→/// A thin immutable container holding *cheaply clonable* gRPC channel handles.
   105→///
   106→/// Cloning an individual client only clones an `Arc` inside the tonic
   107→/// machinery; it does NOT open a fresh TCP connection, so doing so in each
   108→/// request handler is perfectly fine.
   109→#[derive(Clone)]
   110→pub struct AppState {
   111→    pub minting:     MintingServiceClient<Channel>,
   112→    pub composition: CompositionServiceClient<Channel>,
   113→    pub marketplace: MarketplaceServiceClient<Channel>,
   114→    pub governance:  GovernanceServiceClient<Channel>,
