   117→impl AppState {
   118→    /// Connects every gRPC client to the same given endpoint URI
   119→    /// (`http://127.0.0.1:50051` in dev, service-mesh DNS in prod).
   120→    ///
   121→    /// Each client uses an independent HTTP/2 connection in order to keep
   122→    /// per-service flow-control windows separate and maximise throughput under
   123→    /// heavy load.
   124→    pub async fn connect_all<T: Into<String>>(endpoint: T) -> Result<Self, ApiError> {
   125→        let ep: String = endpoint.into();
   126→        let channel    = Channel::from_shared(ep.clone())?
   127→            .tcp_nodelay(true)
   128→            .concurrency_limit(128) // back-pressure against accidental fan-out
   129→            .connect()
   130→            .await?;
   131→
   132→        Ok(Self {
   133→            minting:     MintingServiceClient::new(channel.clone()),
   134→            composition: CompositionServiceClient::new(channel.clone()),
   135→            marketplace: MarketplaceServiceClient::new(channel.clone()),
   136→            governance:  GovernanceServiceClient::new(channel),
   137→        })
   138→    }
