   208→// ---------------------------------------------------------------------------
   209→// Error handling
   210→// ---------------------------------------------------------------------------
   211→
   212→/// Canonical error envelope returned to HTTP clients.  Internally, we rely on
   213→/// [`tonic::Status`] for gRPC, but we do *not* leak internal error codes and
   214→/// messages to the outside world.
   215→#[derive(Debug)]
   216→pub enum ApiError {
   217→    BadRequest(String),
   218→    NotFound(String),
   219→    Upstream(GrpcStatus), // error from micro-service
   220→    Transport(tonic::transport::Error),
   221→    Unexpected(anyhow::Error),
   222→}
   223→
   224→impl fmt::Display for ApiError {
   225→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   226→        use ApiError::*;
   227→
   228→        match self {
   229→            BadRequest(msg) | NotFound(msg) => write!(f, "{msg}"),
   230→            Upstream(status)                => write!(f, "{status}"),
   231→            Transport(err)                  => write!(f, "{err}"),
   232→            Unexpected(err)                 => write!(f, "{err}"),
   233→        }
   234→    }
   235→}
   236→
   237→impl std::error::Error for ApiError {}
   238→
   239→impl From<GrpcStatus> for ApiError {
   240→    fn from(value: GrpcStatus) -> Self {
   241→        ApiError::Upstream(value)
   242→    }
   243→}
   244→
   245→impl From<tonic::transport::Error> for ApiError {
   246→    fn from(value: tonic::transport::Error) -> Self {
   247→        ApiError::Transport(value)
   248→    }
   249→}
   250→
   251→impl From<anyhow::Error> for ApiError {
   252→    fn from(value: anyhow::Error) -> Self {
   253→        ApiError::Unexpected(value)
   254→    }
   255→}
