   257→/// Serialises `ApiError` into an RFC7807 compliant JSON payload.
   258→/// All unrecognised errors are mapped to `500 Internal Server Error` in order
   259→/// to avoid bleeding sensitive information.
   260→impl IntoResponse for ApiError {
   261→    fn into_response(self) -> Response {
   262→        let (status, title) = match &self {
   263→            ApiError::BadRequest(_) => (StatusCode::BAD_REQUEST, "Bad Request"),
   264→            ApiError::NotFound(_)   => (StatusCode::NOT_FOUND, "Not Found"),
   265→            ApiError::Upstream(status) => {
   266→                match status.code() {
   267→                    tonic::Code::NotFound       => (StatusCode::NOT_FOUND, "Not Found"),
   268→                    tonic::Code::InvalidArgument=> (StatusCode::BAD_REQUEST, "Bad Request"),
   269→                    _                           => (StatusCode::BAD_GATEWAY, "Upstream Failure"),
   270→                }
   271→            }
   272→            _ => (StatusCode::INTERNAL_SERVER_ERROR, "Internal Server Error"),
   273→        };
   274→
   275→        let problem = serde_json::json!({
   276→            "type":   "about:blank",
   277→            "title":  title,
   278→            "status": status.as_u16(),
   279→            "detail": self.to_string(),
   280→        });
   281→
   282→        (status, Json(problem)).into_response()
   283→    }
   284→}
