   289→
   290→#[instrument(name = "health", skip_all, fields(client_ip))]
   291→async fn health(State(state): State<AppState>) -> Result<Json<serde_json::Value>, ApiError> {
   292→    // Fan-out health probes to every downstream service in parallel.
   293→    let mut set = JoinSet::new();
   294→
   295→    let cloned = state.clone();
   296→    set.spawn(async move { cloned.minting.health_check(()).await });
   297→    let cloned = state.clone();
   298→    set.spawn(async move { cloned.composition.health_check(()).await });
   299→    let cloned = state.clone();
   300→    set.spawn(async move { cloned.marketplace.health_check(()).await });
   301→    let cloned = state.clone();
   302→    set.spawn(async move { cloned.governance.health_check(()).await });
   303→
   304→    let mut services_healthy = true;
   305→    while let Some(res) = set.join_next().await {
   306→        match res {
   307→            Ok(Ok(_)) => {}
   308→            _ => services_healthy = false,
   309→        }
   310→    }
   311→
   312→    let status = if services_healthy { "ok" } else { "degraded" };
   313→    Ok(Json(serde_json::json!({ "status": status })))
   314→}
   315→
   316→#[instrument(name = "mint_nft", skip(state, headers, payload))]
   317→async fn mint_nft(
   318→    State(state): State<AppState>,
   319→    headers: HeaderMap,
   320→    Json(payload): Json<MintRequest>,
   321→) -> Result<impl IntoResponse, ApiError> {
   322→    // Example of cheap *syntactic* validation – expensive checks are left for
   323→    // the Minting service.
   324→    if payload.metadata_uri.is_empty() {
   325→        return Err(ApiError::BadRequest("metadata_uri must not be empty".into()));
   326→    }
   327→
   328→    // Correlate downstream span with the inbound request
   329→    let span = Span::current();
   330→    span.record("artist_id", &payload.artist_id.as_str());
