   332→    let grpc_req = tonic::Request::new(MintNftRequest {
   333→        nft_id: Uuid::new_v4().to_string(),
   334→        artist_id: payload.artist_id.clone(),
   335→        metadata_uri: payload.metadata_uri.clone(),
   336→        ask_price: payload.ask_price.clone().unwrap_or_default(),
   337→    });
   338→
   339→    let response: MintNftResponse = state.minting.clone().mint_nft(grpc_req).await?.into_inner();
   340→
   341→    Ok((
   342→        StatusCode::CREATED,
   343→        Json(MintResponse {
   344→            nft_id: response.nft_id,
   345→        }),
   346→    ))
   347→}
