   349→#[instrument(name = "get_nft", skip(state))]
   350→async fn get_nft(
   351→    State(state): State<AppState>,
   352→    Path(nft_id): Path<String>,
   353→) -> Result<Json<Nft>, ApiError> {
   354→    let grpc_req = tonic::Request::new(QueryNftRequest { nft_id: nft_id.clone() });
   355→    let nft: QueryNftResponse = state.minting.clone().get_nft(grpc_req).await?.into_inner();
   356→
   357→    if nft.nft_id.is_empty() {
   358→        return Err(ApiError::NotFound(format!("NFT {nft_id} does not exist")));
   359→    }
   360→
   361→    Ok(Json(Nft {
   362→        nft_id: nft.nft_id,
   363→        owner: nft.owner,
   364→        metadata_uri: nft.metadata_uri,
   365→        ask_price: if nft.ask_price.is_empty() { None } else { Some(nft.ask_price) },
   366→        created_at: nft.created_at,
   367→    }))
   368→}
