   370→#[instrument(name = "list_nfts", skip(state))]
   371→async fn list_nfts(
   372→    State(state): State<AppState>,
   373→    Query(pg): Query<Pagination>,
   374→) -> Result<Json<Paginated<Nft>>, ApiError> {
   375→    // The `list_nfts` RPC accepts offset/limit rather than page/per_page.
   376→    let offset            = (pg.page.saturating_sub(1) * pg.per_page) as u64;
   377→    let grpc_req          = tonic::Request::new(proto::minting::ListNftsRequest {
   378→        offset,
   379→        limit: pg.per_page as u64,
   380→    });
   381→    let list_resp         = state.minting.clone().list_nfts(grpc_req).await?.into_inner();
   382→    let total             = list_resp.total as u32;
   383→    let data: Vec<Nft>    = list_resp
   384→        .nfts
   385→        .into_iter()
   386→        .map(|n| Nft {
   387→            nft_id: n.nft_id,
   388→            owner: n.owner,
   389→            metadata_uri: n.metadata_uri,
   390→            ask_price: if n.ask_price.is_empty() { None } else { Some(n.ask_price) },
   391→            created_at: n.created_at,
   392→        })
   393→        .collect();
   394→
   395→    Ok(Json(Paginated {
   396→        data,
   397→        page: pg.page,
   398→        per_page: pg.per_page,
   399→        total,
   400→    }))
   401→}
   402→
   403→#[instrument(name = "cast_vote", skip(state, payload))]
   404→async fn cast_vote(
   405→    State(state): State<AppState>,
   406→    Json(payload): Json<VoteRequest>,
   407→) -> Result<Json<VoteResponse>, ApiError> {
   408→    if !["yes", "no", "abstain"].contains(&payload.choice.to_lowercase().as_str()) {
   409→        return Err(ApiError::BadRequest("choice must be Yes|No|Abstain".into()));
   410→    }
   411→
   412→    let grpc_req = tonic::Request::new(proto::governance::CastVoteRequest {
   413→        proposal_id: payload.proposal_id,
   414→        voter: payload.voter,
   415→        choice: payload.choice,
   416→    });
   417→
   418→    let resp = state
   419→        .governance
   420→        .clone()
   421→        .cast_vote(grpc_req)
   422→        .await?
   423→        .into_inner();
   424→
   425→    Ok(Json(VoteResponse { accepted: resp.accepted }))
   426→}
