     2→//! Persistent world-state database abstraction for CanvasChain Symphony.
     3→//!
     4→//! The `StateDb` is the canonical source of truth for chain execution.  It
     5→//! stores **accounts**, **contract byte-code** and **key–value storage** for
     6→//! every smart contract.  Each block commit generates a deterministic *state
     7→//! root* (a Blake3 Merkle accumulation of all key–value pairs) that can later
     8→//! be proven against light-client requests or off-chain indexers.
     9→//!
    10→//! Elasticity requirements of the Symphony runtime dictate that the database
    11→//! must support:
    12→//!   * atomic multi-key updates (Write-Set)
    13→//!   * cheap, read-only snapshots per block height
    14→//!   * forward-only pruning (retain the last *N* roots and fast-prune the rest)
    15→//!
    16→//! This implementation relies on `sled` for embedded, high-performance storage
    17→//! and an append-only **versioned column family** layout to avoid write
    18→//! amplification while retaining historical states.
    19→
    20→use std::{
    21→    path::{Path, PathBuf},
    22→    sync::{
    23→        atomic::{AtomicU64, Ordering},
    24→        Arc,
    25→    },
    26→};
    27→
    28→use blake3::Hasher;
    29→use parking_lot::RwLock;
    30→use serde::{de::DeserializeOwned, Deserialize, Serialize};
    31→use sled::{
    32→    transaction::{
    33→        ConflictableTransactionError, TransactionError, TransactionResult, Transactional,
    34→        TransactionalTree,
    35→    },
    36→    Db, IVec,
    37→};
    38→use thiserror::Error;
    39→use tokio::sync::broadcast;
    40→
    41→/// Logical identifier for an account or contract.
    42→pub type Address = [u8; 32];
    43→
    44→/// Hashed representation of the entire world state for a given block height.
    45→pub type StateRoot = [u8; 32];
    46→
    47→/// Ordering key prefix for versioned writes: `{height}/{raw_key}`.
    48→///
    49→/// We keep the numerical height in big-endian to preserve lexicographic order.
    50→fn compose_versioned_key(height: u64, raw_key: &[u8]) -> Vec<u8> {
    51→    let mut out = Vec::with_capacity(8 + raw_key.len());
    52→    out.extend_from_slice(&height.to_be_bytes());
    53→    out.extend_from_slice(raw_key);
    54→    out
    55→}
    56→
    57→/// Decode a versioned key returning `(height, raw_key)`.
    58→fn split_versioned_key(versioned: &[u8]) -> (u64, &[u8]) {
    59→    let (height_bytes, raw) = versioned.split_at(8);
    60→    (
    61→        u64::from_be_bytes(height_bytes.try_into().expect("8 bytes")),
    62→        raw,
    63→    )
    64→}
    65→
    66→/// High-level account record stored in the `StateDb`.
    67→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
    68→pub struct AccountState {
    69→    pub balance: u128,
    70→    pub nonce: u64,
    71→    /// Hash of contract bytecode (if any).
    72→    pub code_hash: Option<[u8; 32]>,
    73→    /// Merklized root of the contract storage tree.
    74→    pub storage_root: [u8; 32],
    75→}
    76→
    77→impl Default for AccountState {
    78→    fn default() -> Self {
    79→        Self {
    80→            balance: 0,
    81→            nonce: 0,
    82→            code_hash: None,
    83→            storage_root: [0u8; 32],
    84→        }
    85→    }
    86→}
    87→
    88→/// Arbitrary write operation encoded in a block's *write-set*.
    89→#[derive(Debug, Clone, Serialize, Deserialize)]
    90→pub enum WriteOp<V> {
    91→    Put(Vec<u8>, V),
    92→    Delete(Vec<u8>),
    93→}
    94→
    95→/// Aggregated writes performed by the execution engine for a single block.
    96→pub type WriteSet<V> = Vec<WriteOp<V>>;
    97→
    98→/// Notification emitted after every successful `commit_block`.
    99→#[derive(Debug, Clone)]
   100→pub struct StateCommitEvent {
   101→    pub block_height: u64,
   102→    pub new_state_root: StateRoot,
   103→}
   104→
   105→/// Custom errors bubbled up by the `StateDb`.
   106→#[derive(Debug, Error)]
   107→pub enum StateDbError {
   108→    #[error("sled error: {0}")]
   109→    Sled(#[from] sled::Error),
   110→
   111→    #[error("serialization error: {0}")]
   112→    Bincode(#[from] bincode::Error),
   113→
   114→    #[error("conflicting write transaction")]
   115→    Conflict,
   116→
   117→    #[error("requested historical height ({requested}) is pruned – oldest available: {oldest}")]
   118→    Pruned { requested: u64, oldest: u64 },
   119→}
   120→
   121→/// Primary database wrapper offering high-level typed APIs.
   122→pub struct StateDb {
   123→    db: Db,
   124→    /// Tree for versioned state entries.
   125→    tree: sled::Tree,
   126→    /// Monotonically increasing block height.
   127→    current_height: AtomicU64,
   128→    /// Oldest height still retained (everything below is pruned).
   129→    oldest_height: AtomicU64,
   130→    /// Broadcast channel for commit notifications.
   131→    event_tx: broadcast::Sender<StateCommitEvent>,
   132→    /// Path on disk (used on `prune`).
   133→    _path: PathBuf,
   134→    /// Global rw-lock for snapshot safety.
   135→    guard: Arc<RwLock<()>>,
   136→}
   137→
   138→impl StateDb {
   139→    /// Open or create a new `StateDb` at `path`.
   140→    pub fn open<P: AsRef<Path>>(path: P) -> Result<Self, StateDbError> {
   141→        let db = sled::open(&path)?;
   142→        let tree = db.open_tree("state")?;
   143→
   144→        // Determine the current and oldest heights by scanning prefix keys.
   145→        let (mut current_height, mut oldest_height) = (0u64, u64::MAX);
   146→        for key in tree.iter().keys() {
   147→            let k = key?;
   148→            let (h, _) = split_versioned_key(&k);
   149→            if h > current_height {
   150→                current_height = h;
   151→            }
   152→            if h < oldest_height {
   153→                oldest_height = h;
   154→            }
   155→        }
   156→        if oldest_height == u64::MAX {
   157→            oldest_height = 0;
   158→        }
   159→
   160→        let (event_tx, _) = broadcast::channel(64);
   161→        Ok(Self {
   162→            db,
   163→            tree,
   164→            current_height: AtomicU64::new(current_height),
   165→            oldest_height: AtomicU64::new(oldest_height),
   166→            event_tx,
   167→            _path: path.as_ref().to_path_buf(),
   168→            guard: Arc::new(RwLock::new(())),
   169→        })
   170→    }
   171→
   172→    /// Subscribe to state-commit events.
   173→    pub fn subscribe(&self) -> broadcast::Receiver<StateCommitEvent> {
   174→        self.event_tx.subscribe()
   175→    }
   176→
   177→    /// Retrieve the value associated with `raw_key` *at the latest height*.
   178→    pub fn get<V: DeserializeOwned>(&self, raw_key: &[u8]) -> Result<Option<V>, StateDbError> {
   179→        let height = self.current_height.load(Ordering::SeqCst);
   180→        self.get_at(height, raw_key)
   181→    }
   182→
   183→    /// Retrieve a historical value at `height`.
   184→    pub fn get_at<V: DeserializeOwned>(
   185→        &self,
   186→        height: u64,
   187→        raw_key: &[u8],
   188→    ) -> Result<Option<V>, StateDbError> {
   189→        let oldest = self.oldest_height.load(Ordering::SeqCst);
   190→        if height < oldest {
   191→            return Err(StateDbError::Pruned {
   192→                requested: height,
   193→                oldest,
   194→            });
   195→        }
   196→
   197→        let _r = self.guard.read(); // protect against concurrent pruning
   198→        let versioned_key = compose_versioned_key(height, raw_key);
   199→        Ok(self
   200→            .tree
   201→            .get(versioned_key)?
   202→            .map(|ivec| bincode::deserialize(&ivec))
   203→            .transpose()?)
   204→    }
   205→
   206→    /// Store a single value at the *next* block height.
   207→    ///
   208→    /// This is mostly useful for tests; production execution typically uses
   209→    /// `commit_block` that atomically writes a full `WriteSet`.
   210→    pub fn put<V: Serialize>(&self, raw_key: &[u8], value: &V) -> Result<(), StateDbError> {
   211→        self.commit_block::<V>(WriteSet::from([WriteOp::Put(
   212→            raw_key.to_vec(),
   213→            value.clone(),
   214→        )]))
   215→        .map(|_| ())
   216→    }
   217→
   218→    /// Atomically apply a `write_set`, advance `current_height` and
   219→    /// deterministically compute the new `StateRoot`.
   220→    pub fn commit_block<V: Serialize>(&self, write_set: WriteSet<V>) -> Result<StateRoot, StateDbError> {
   221→        let new_height = self.current_height.load(Ordering::SeqCst) + 1;
   222→        {
   223→            // Acquire read-lock to forbid pruning during commit.
   224→            let _r = self.guard.read();
   225→            // --- transactional write ---
   226→            let result: TransactionResult<(), StateDbError, _> =
   227→                (&self.tree).transaction(|tx_tree| {
   228→                    for op in &write_set {
   229→                        match op {
   230→                            WriteOp::Put(k, v) => {
   231→                                let vk = compose_versioned_key(new_height, k);
   232→                                let bytes = bincode::serialize(v)?;
   233→                                tx_tree.insert(vk, bytes)
   234→                                    .map_err(|e| ConflictableTransactionError::Abort(StateDbError::Sled(e)))?;
   235→                            }
   236→                            WriteOp::Delete(k) => {
   237→                                let vk = compose_versioned_key(new_height, k);
   238→                                tx_tree.remove(vk)
   239→                                    .map_err(|e| ConflictableTransactionError::Abort(StateDbError::Sled(e)))?;
   240→                            }
   241→                        }
   242→                    }
   243→                    Ok(())
   244→                });
   245→
   246→            match result {
   247→                Ok(_) => {}
   248→                Err(TransactionError::Storage(e)) => return Err(StateDbError::Sled(e)),
   249→                Err(TransactionError::Abort(e)) => return Err(e),
   250→            }
   251→        }
   252→
   253→        // Sync to disk.
   254→        self.db.flush()?;
   255→
   256→        // Re-compute and persist new root.
   257→        let new_root = self.compute_state_root(new_height)?;
   258→        self.current_height.store(new_height, Ordering::SeqCst);
   259→
   260→        // Notify subscribers – ignore send failures (no active listeners).
   261→        let _ = self
   262→            .event_tx
   263→            .send(StateCommitEvent { block_height: new_height, new_state_root: new_root });
   264→
   265→        Ok(new_root)
