    68→    InsufficientStake { requested: u128, available: u128 },
    69→    #[error("staker `{0}` is not registered")]
    70→    UnknownStaker(StakerId),
    71→    #[error("VRF verification failed: {0}")]
    72→    VrfFailed(String),
