    99→/// Abstraction for a Verifiable Random Function provider.
   100→pub trait VrfProvider: Send + Sync + 'static {
   101→    /// Produces a VRF proof and output hash for `message` using the *private*
   102→    /// part of the provider implementation.
   103→    fn prove(&self, message: &[u8]) -> (Vec<u8> /*proof*/, Vec<u8> /*hash*/);
   104→
   105→    /// Verify a proof & hash produced by `prove`.
   106→    fn verify(
   107→        &self,
   108→        public_key: &[u8],
   109→        message: &[u8],
   110→        proof: &[u8],
   111→        hash: &[u8],
   112→    ) -> std::result::Result<(), String>;
   113→}
   114→
   115→/// Fallback VRF provider that is *not* secure; meant only for local-dev and
   116→/// CI where cryptography isn’t the focus.  It deterministically hashes the
   117→/// message + static `private_key`.
   118→pub struct Sha256Vrf {
   119→    private_key: Vec<u8>,
   120→}
   121→
   122→impl Sha256Vrf {
   123→    pub fn new() -> Self {
   124→        let mut pk = vec![0u8; 32];
   125→        OsRng.fill_bytes(&mut pk);
   126→        Self { private_key: pk }
   127→    }
   128→}
   129→
   130→impl VrfProvider for Sha256Vrf {
   131→    fn prove(&self, message: &[u8]) -> (Vec<u8>, Vec<u8>) {
   132→        let mut hasher = Sha256::new();
   133→        hasher.update(&self.private_key);
