### 3.2 Minting Service Changes

#### File: `services/minting_service/src/logic/nft_factory.rs`

**New Methods:**

```rust
impl<S, C, E> NftFactory<S, C, E>
where
    S: CryptoSigner + 'static,
    C: BlockchainClient + 'static,
    E: EventPublisher + 'static,
{
    /// Fractionalize an existing NFT into fungible fraction tokens
    #[instrument(skip_all, level = "info", fields(nft_id = %req.nft_id))]
    pub async fn fractionalize_nft(&self, req: FractionalizeRequest) -> Result<FractionalizeResponse, FactoryError> {
        // 1. Validate the request
        self.validate_fractionalize_request(&req)?;

        // 2. Build fractionalization payload
        let fraction_token_id = Uuid::new_v4();
        let payload = self.build_fractionalize_payload(&req, &fraction_token_id).await?;

        // 3. Sign the payload
        let signature = self.signer.sign(&payload).await?;

        // 4. Submit to chain
        let tx_hash = self.chain.submit_fractionalize(FractionalizePayload {
            nft_id: req.nft_id.clone(),
            fraction_token_id: fraction_token_id.to_string(),
            total_fractions: req.total_fractions,
            min_trade_unit: req.min_trade_unit,
            reconstitutable: req.reconstitutable,
            buyout_price: req.buyout_price,
            signature,
        }).await?;

        // 5. Publish success event
        self.bus.publish(
            &self.config.event_topic_fractionalized,
            &FractionalizedEvent {
                nft_id: req.nft_id.clone(),
                fraction_token_id: fraction_token_id.to_string(),
                total_fractions: req.total_fractions,
                owner: req.owner_wallet.clone(),
                timestamp_ms: now_millis(),
            },
        ).await?;

        Ok(FractionalizeResponse {
            fraction_token_id: fraction_token_id.to_string(),
            tx_hash,
            success: true,
        })
    }

    fn validate_fractionalize_request(&self, req: &FractionalizeRequest) -> Result<(), FactoryError> {
        if req.total_fractions < 2 {
            return Err(FactoryError::Validation("must create at least 2 fractions".into()));
        }
        if req.total_fractions > self.config.max_fractions {
            return Err(FactoryError::Validation(format!(
                "cannot exceed {} fractions",
                self.config.max_fractions
            )));
        }
        if req.min_trade_unit == 0 || req.min_trade_unit > req.total_fractions {
            return Err(FactoryError::Validation("invalid min_trade_unit".into()));
        }
        Ok(())
    }
}
```

#### File: `services/minting_service/src/rpc_server.rs`

**New gRPC Endpoint:**

```rust
/// gRPC service implementation for fractionalization
#[tonic::async_trait]
impl FractionalService for MintingRpcServer {
    async fn fractionalize(
        &self,
        request: Request<FractionalizeRequest>,
    ) -> Result<Response<FractionalizeResponse>, Status> {
        let req = request.into_inner();

        // Validate signature
        self.verify_signature(&req.owner_wallet, &req.signature).await
            .map_err(|e| Status::unauthenticated(e.to_string()))?;

        // Execute fractionalization
        let response = self.factory
            .fractionalize_nft(req)
            .await
            .map_err(|e| Status::internal(e.to_string()))?;

        Ok(Response::new(response))
    }

    async fn reconstitute(
