impl StakePool {
    /// Calculate staking rewards distribution including fraction holders
    pub async fn distribute_rewards_to_fraction_holders(
        &self,
        nft_id: &Uuid,
        total_reward: u128,
    ) -> Result<Vec<(StakerId, u128)>, StakingError> {
        // Get all fraction holders for this NFT
        let holders = self.get_fraction_holders(nft_id).await?;

        // Calculate each holder's share proportionally
        let distributions: Vec<(StakerId, u128)> = holders
            .iter()
            .map(|(staker_id, balance, total_supply)| {
                let share = (total_reward * *balance as u128) / *total_supply as u128;
                (staker_id.clone(), share)
            })
            .collect();

        // Emit distribution events
        for (staker, amount) in &distributions {
            self.event_tx.send(StakingEvent::FractionRewardDistributed {
                nft_id: nft_id.to_string(),
                staker: staker.clone(),
                amount: *amount,
            }).ok();
        }

        Ok(distributions)
    }
}
