            .save_weighted_vote(proposal_id, voter, choice, voting_weight)
            .await?;

        self.events
            .publish(GovernanceEvent::WeightedVoteCast {
                proposal_id,
                voter: voter.to_owned(),
                choice,
                weight: voting_weight,
            })
            .await;

        Ok(())
    }

    /// Calculate voting power including fractional ownership
    async fn calculate_voting_power(&self, voter: &str) -> Result<u64, ProposalError> {
        // Get whole NFT count
        let whole_nft_power = self.get_whole_nft_count(voter).await? * 100;

        // Get fractional holdings and sum weighted by ownership %
        let fraction_holdings = self.get_fraction_holdings(voter).await?;
        let fraction_power: u64 = fraction_holdings
            .iter()
            .map(|h| {
                let ownership_pct = (h.balance as f64 / h.total_supply as f64) * 100.0;
                ownership_pct as u64
            })
            .sum();

        Ok(whole_nft_power + fraction_power)
    }
}
