#[instrument(name = "fractionalize_nft", skip(state, headers, payload))]
async fn fractionalize_nft(
    State(state): State<AppState>,
    Path(nft_id): Path<String>,
    headers: HeaderMap,
    Json(payload): Json<FractionalizeRequestBody>,
) -> Result<impl IntoResponse, ApiError> {
    // Validate request
    if payload.total_fractions < 2 {
        return Err(ApiError::BadRequest("must create at least 2 fractions".into()));
    }

    // Forward to minting service via gRPC
    let grpc_req = tonic::Request::new(proto::fractional::FractionalizeRequest {
        nft_id,
        owner_wallet: payload.owner_wallet,
        total_fractions: payload.total_fractions,
        min_trade_unit: payload.min_trade_unit.unwrap_or(1),
        reconstitutable: payload.reconstitutable.unwrap_or(true),
        buyout_price: payload.buyout_price,
        signature: payload.signature,
    });

    let response = state.minting.clone()
        .fractionalize(grpc_req)
        .await?
        .into_inner();

    Ok((
        StatusCode::CREATED,
        Json(FractionalizeResponseBody {
            fraction_token_id: response.fraction_token_id,
            tx_hash: response.tx_hash,
            success: response.success,
        }),
    ))
}

