    /// NFT is actively fractionalized
    Active,
    /// Buyout initiated, fractions can be redeemed
    BuyoutInProgress { initiator: WalletAddress, deadline: u64 },
    /// NFT has been reconstituted to a single owner
    Reconstituted,
    /// Fractionalized NFT has been dissolved (rare edge case)
    Dissolved,
}
