**Modified Outcome Calculation:**

```rust
/// Computes outcome using weighted votes
fn compute_weighted_outcome(proposal: &Proposal, params: &GovernanceParameters) -> ProposalOutcome {
    let total_weight: u64 = proposal.weighted_votes.values().map(|(_, w)| w).sum();

    if total_weight == 0 {
        return ProposalOutcome::QuorumNotMet;
    }

    let yes_weight: u64 = proposal
        .weighted_votes
        .iter()
        .filter(|(_, (choice, _))| *choice == VoteChoice::Yes)
        .map(|(_, (_, weight))| weight)
        .sum();

    let quorum_met = total_weight >= params.required_quorum_weight;

    if !quorum_met {
        return ProposalOutcome::QuorumNotMet;
    }

    let yes_pct = (yes_weight * 100) / total_weight;
    if yes_pct >= params.pass_threshold_pct as u64 {
        ProposalOutcome::Accepted
    } else {
        ProposalOutcome::Rejected
    }
}
